trait Repository {
    fn save(&self, data: String);
}

struct PostgresRepo;
impl Repository for PostgresRepo {
    fn save(&self, data: String) {
        println!("Saving '{}' to Postgres...", data);
    }
}

// Service depends on Trait, not implementation
fn create_user(repo: &impl Repository, name: String) {
    repo.save(name);
}

fn main() {
    let repo = PostgresRepo;
    create_user(&repo, String::from("Alice"));
}
